import {
  OnboardingStepper,
  SelectChoiceCard,
  SelectChoiceCardGroup,
} from "@procertus-ui/ui-lib";
import {
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardList,
  CardTitle,
  Empty,
  EmptyDescription,
  EmptyIcon,
  EmptyTitle,
  Field,
  FieldContent,
  FieldGroup,
  FieldLabel,
  Switch,
  Textarea,
  useConfirm,
  useIsMobile,
} from "@procertus-ui/ui";
import { HierarchySquare02Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";

import { CERTIFICATION_REQUEST_STEP_IDS } from "../../certification-request/types";
import { useCertificationRequestWizardModel } from "../../certification-request/model";
import {
  CertificationIntentPicker,
  defaultCertificationIntentOptionsEn,
} from "../certification-intent-picker";
import type { CertificationIntentId } from "../certification-intent-picker";
import { ProductMultiSelect } from "../product-multi-select";
import { ProductTreePanel } from "../product-tree-panel";
import type { ProductTreeProductNode } from "../product-tree-panel";
import { RequestPackageReview } from "../request-package-review";
import { CompactWizardTimeline } from "./CompactWizardTimeline";
import { DraftCardDescription, sortDraftsByIntentAndProduct } from "./draft-selection-presentation";
import { buildRulesetDocumentsForInquiries } from "./build-ruleset-documents-for-inquiries";
import type {
  CertificationRequestWizardViewProps,
  UseCertificationRequestWizardViewOptions,
} from "./certification-request-wizard-types";
import { useMemo, useState } from "react";
import { StepLayout, DownloadableDocumentsList } from "@procertus-ui/ui-lib";

const certStepReview = CERTIFICATION_REQUEST_STEP_IDS.indexOf("review");

export function useCertificationRequestWizardView(
  options: UseCertificationRequestWizardViewOptions,
): CertificationRequestWizardViewProps {
  const { onCancel, onRequestCreated, onComplete, reviewRequester } = options;
  const model = useCertificationRequestWizardModel({ onCancel, onRequestCreated, onComplete });
  const confirm = useConfirm();
  const authenticated = model.mode === "authenticated";
  const isMobile = useIsMobile();
  const splitProductInquirySteps =
    authenticated && isMobile && model.detailsStep.detailsUseProductTree;
  const [mobileDetailsStep, setMobileDetailsStep] = useState<"product" | "inquiries">("product");
  const effectiveMobileDetailsStep =
    splitProductInquirySteps && model.activeStep === 1 ? mobileDetailsStep : "product";

  const mobileStepper = useMemo(() => {
    if (!splitProductInquirySteps) return model.stepper;

    const [intentStep, productStep, draftsStep, reviewStep] = model.stepper.steps;
    return {
      activeStep:
        model.activeStep < 1
          ? model.activeStep
          : model.activeStep === 1
            ? effectiveMobileDetailsStep === "product"
              ? 1
              : 2
            : model.activeStep + 1,
      steps: [
        intentStep,
        productStep,
        {
          id: "inquiries",
          title: "Aanvragen",
          description: model.detailsStep.selectedProduct
            ? "Kies certificaten en attesten"
            : "Selecteer eerst een product",
          available: Boolean(model.detailsStep.selectedProduct),
        },
        draftsStep,
        reviewStep,
      ].filter((step): step is NonNullable<typeof step> => step != null),
      onStepChange: (step: number) => {
        if (step <= 1) {
          setMobileDetailsStep("product");
          model.stepper.onStepChange(Math.min(step, 1));
          return;
        }
        if (step === 2) {
          if (model.detailsStep.selectedProduct) {
            model.stepper.onStepChange(1);
            setMobileDetailsStep("inquiries");
          }
          return;
        }
        setMobileDetailsStep("product");
        model.stepper.onStepChange(step - 1);
      },
    };
  }, [
    effectiveMobileDetailsStep,
    model.detailsStep.selectedProduct,
    model.stepper,
    model.activeStep,
    splitProductInquirySteps,
  ]);

  const layout =
    splitProductInquirySteps && model.activeStep === 1
      ? {
          ...model.layout,
          title:
            effectiveMobileDetailsStep === "product"
              ? "Selecteer het producttype"
              : "Kies de aanvragen",
          description:
            effectiveMobileDetailsStep === "product"
              ? "Kies eerst een product in de beslissingsboom. Daarna selecteer je de beschikbare certificaten en attesten."
              : "Selecteer welke certificaten en attesten je voor dit product wilt toevoegen.",
          stepLabel: `Stap ${mobileStepper.activeStep + 1} van ${mobileStepper.steps.length}`,
          backAction:
            effectiveMobileDetailsStep === "inquiries"
              ? { label: "Terug", onClick: () => setMobileDetailsStep("product") }
              : model.layout.backAction,
          primaryAction:
            effectiveMobileDetailsStep === "product"
              ? {
                  label: "Verder",
                  onClick: () => setMobileDetailsStep("inquiries"),
                  disabled: !model.detailsStep.selectedProduct,
                }
              : model.layout.primaryAction,
        }
      : model.layout;

  const primaryAction =
    model.activeStep === certStepReview
      ? {
          ...layout.primaryAction,
          onClick: async () => {
            const confirmed = confirm
              ? await confirm(
                  "Aanvraagpakket versturen?",
                  "Na indiening wordt dit pakket met alle onderliggende certificatie- en attestvragen doorgestuurd naar PROCERTUS voor behandeling.",
                )
              : true;
            if (confirmed) {
              layout.primaryAction.onClick();
            }
          },
        }
      : layout.primaryAction;

  const includedReviewInquiries = useMemo(() => {
    const selected = new Set(model.draftsStep.includedDraftIds);
    return model.draftsStep.drafts.filter((d) => selected.has(d.id));
  }, [model.draftsStep.drafts, model.draftsStep.includedDraftIds]);

  const rulesetDocuments = useMemo(
    () => buildRulesetDocumentsForInquiries(includedReviewInquiries),
    [includedReviewInquiries],
  );

  const sortedDrafts = useMemo(
    () => sortDraftsByIntentAndProduct(model.draftsStep.drafts),
    [model.draftsStep.drafts],
  );

  const onDraftIncludedChange = (draftId: string, checked: boolean) => {
    const current = model.draftsStep.includedDraftIds;
    model.draftsStep.onIncludedDraftIdsChange(
      checked
        ? Array.from(new Set([...current, draftId]))
        : current.filter((id) => id !== draftId),
    );
  };

  const rulesetDocumentsDescription =
    includedReviewInquiries.length > 0
      ? `Documenten op basis van je ${includedReviewInquiries.length} geselecteerde ${includedReviewInquiries.length === 1 ? "aanvraag" : "aanvragen"} (prototype — downloadlinks zijn gemockt).`
      : "Selecteer eerst aanvragen in de vorige stap om relevante documenten te zien (prototype).";

  const stepperNode = authenticated ? (
    <>
      <div className="pt-region md:hidden">
        <CompactWizardTimeline model={mobileStepper} />
      </div>
      <OnboardingStepper
        {...model.stepper}
        className="hidden max-w-none md:block"
        orientation="vertical"
        interactive
      />
    </>
  ) : (
    <OnboardingStepper {...model.stepper} orientation="horizontal" interactive />
  );

  return {
    stepLayout: {
      className: authenticated ? "max-w-none" : "w-full",
      layout: authenticated ? "fill-parent" : "default",
      flush: authenticated,
      stepperPosition: authenticated ? "start" : "top",
      variant: "wizard",
      stepper: stepperNode,
      title: layout.title,
      description: layout.description,
      stepLabel: layout.stepLabel,
      backAction: layout.backAction,
      secondaryAction: layout.secondaryAction,
      primaryAction,
    },
    showIntentStep: model.activeStep === 0,
    intentStep: model.intentStep,
    showDetailsStep: model.activeStep === 1,
    splitProductInquirySteps,
    effectiveMobileDetailsStep,
    detailsStep: model.detailsStep,
    showDraftsStep: model.activeStep === 2,
    draftsStep: model.draftsStep,
    sortedDrafts,
    onDraftIncludedChange,
    showReviewStep: model.activeStep === certStepReview,
    mode: model.mode,
    reviewRequester,
    reviewStep: model.reviewStep,
    rulesetDocumentsDescription,
    rulesetDocuments,
    rulesetEmptyContent: (
      <p className="text-sm text-muted-foreground">
        Geen geselecteerde aanvragen — vink in de vorige stap minstens één aanvraag aan om
        documentatie te tonen.
      </p>
    ),
  };
}

export function CertificationRequestWizardView(props: CertificationRequestWizardViewProps) {
  const {
    stepLayout,
    showIntentStep,
    intentStep,
    showDetailsStep,
    splitProductInquirySteps,
    effectiveMobileDetailsStep,
    detailsStep,
    showDraftsStep,
    draftsStep,
    sortedDrafts,
    onDraftIncludedChange,
    showReviewStep,
    mode,
    reviewRequester,
    reviewStep,
    rulesetDocumentsDescription,
    rulesetDocuments,
    rulesetEmptyContent,
  } = props;

  return (
    <StepLayout {...stepLayout}>
      {showIntentStep ? (
        <CertificationIntentPicker
          value={intentStep.value as CertificationIntentId | undefined}
          onValueChange={(intent) => intentStep.onValueChange(intent)}
          options={defaultCertificationIntentOptionsEn}
        />
      ) : null}

      {showDetailsStep ? (
        <div className="space-y-4">
          {detailsStep.canUseFreeform ? (
            <div className="grid gap-4 lg:grid-cols-[minmax(0,1fr)_minmax(18rem,24rem)]">
              <FieldGroup>
                <Field>
                  <FieldLabel htmlFor="request-context">Aanvraagcontext</FieldLabel>
                  <FieldContent>
                    <Textarea
                      id="request-context"
                      value={detailsStep.requestText}
                      onChange={(event) => detailsStep.onRequestTextChange(event.target.value)}
                      placeholder="Bijvoorbeeld: technisch attest voor een innovatieve toepassing op een concrete werf..."
                      className="min-h-56"
                    />
                  </FieldContent>
                </Field>
              </FieldGroup>
              <Card className="h-fit gap-section p-section">
                <CardHeader className="gap-micro px-0">
                  <CardTitle>Wat moet je beschrijven?</CardTitle>
                  <CardDescription>
                    Voor {detailsStep.selectedIntentLabel} volstaat in dit prototype een korte maar
                    concrete context.
                  </CardDescription>
                </CardHeader>
                <CardContent className="px-0">
                  <ul className="list-disc space-y-component pl-component text-sm leading-normal text-muted-foreground">
                    <li>Waarvoor je het attest of de certificatie nodig hebt.</li>
                    <li>Welke toepassing, werf of situatie relevant is.</li>
                    <li>Eventuele productinformatie als die helpt bij de beoordeling.</li>
                  </ul>
                </CardContent>
              </Card>
            </div>
          ) : null}

          {detailsStep.detailsUseProductTree ? (
            <div
              className={
                splitProductInquirySteps
                  ? "grid gap-4"
                  : "grid gap-4 xl:grid-cols-[minmax(0,1fr)_minmax(18rem,24rem)]"
              }
            >
              {!splitProductInquirySteps || effectiveMobileDetailsStep === "product" ? (
                <ProductTreePanel
                  className="max-w-none"
                  title="Product zoeken"
                  description="Drill down in de Procertus-beslissingsboom of filter op productnaam."
                  searchValue={detailsStep.productTree.searchValue}
                  onSearchChange={detailsStep.productTree.onSearchChange}
                  searchPlaceholder="Zoek product of categorie..."
                  actions={
                    <label className="flex items-center gap-2 rounded-md border border-border/60 px-3 py-2 text-sm">
                      <Switch
                        checked={detailsStep.productTree.hideUnavailableProducts}
                        onCheckedChange={detailsStep.productTree.onHideUnavailableProductsChange}
                        aria-label="Toon alleen beschikbare producttypes"
                      />
                      Alleen beschikbaar
                    </label>
                  }
                  nodes={detailsStep.productTree.nodes}
                  expandedIds={detailsStep.productTree.expandedIds}
                  onCollapseAll={detailsStep.productTree.collapseAll}
                  onExpandAll={detailsStep.productTree.expandAll}
                  onToggle={detailsStep.productTree.onToggle}
                  onSelectProduct={(product: ProductTreeProductNode) =>
                    detailsStep.productTree.onSelectProduct(product)
                  }
                  showSearch
                />
              ) : null}
              {(!splitProductInquirySteps || effectiveMobileDetailsStep === "inquiries") &&
              detailsStep.selectedProduct ? (
                <Card className="h-fit xl:sticky xl:top-component xl:max-h-[calc(100svh-12rem)]">
                  <CardHeader>
                    <CardTitle>Certificatie- en attesteringsopties</CardTitle>
                    <CardDescription>
                      Bekijk alle mogelijke aanvragen voor dit product. Alleen mogelijke opties
                      kunnen worden geselecteerd.
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="min-h-0 space-y-4 xl:overflow-y-auto">
                    <div className="rounded-md border border-border/60 bg-muted/20 p-3">
                      <p className="font-medium">{detailsStep.selectedProduct.label}</p>
                      <p className="text-sm text-muted-foreground">
                        {detailsStep.selectedProduct.path}
                      </p>
                    </div>
                    <ProductMultiSelect
                      selectedIds={detailsStep.selectedEntryIds}
                      onChange={detailsStep.onSelectedEntryIdsChange}
                      options={detailsStep.productOptions}
                      legend="Toe te voegen aanvragen"
                      description="Niet-beschikbare types blijven zichtbaar zodat duidelijk is waarom ze niet kunnen worden aangevraagd."
                      emptyMessage="Selecteer eerst een producttype om de opties te zien."
                    />
                  </CardContent>
                </Card>
              ) : !splitProductInquirySteps ? (
                <Card className="h-fit xl:sticky xl:top-component">
                  <CardContent className="p-section">
                    <Empty>
                      <EmptyIcon>
                        <HugeiconsIcon icon={HierarchySquare02Icon} strokeWidth={1.5} />
                      </EmptyIcon>
                      <EmptyTitle>Selecteer eerst een producttype</EmptyTitle>
                      <EmptyDescription>
                        Kies links een product in de catalogus. Daarna tonen we hier de beschikbare
                        certificaten en attesten die je aan deze aanvraag kunt toevoegen.
                      </EmptyDescription>
                    </Empty>
                  </CardContent>
                </Card>
              ) : null}
            </div>
          ) : null}
        </div>
      ) : null}

      {showDraftsStep ? (
        <div className="space-y-section">
          <Card className="gap-section p-section">
            <CardHeader className="gap-micro px-0">
              <CardTitle>Meerdere certificatie- en attestvragen in één aanvraag</CardTitle>
              <CardDescription>
                Dit pakket kan meerdere certificatie- en attestvragen bundelen. Voeg extra vragen toe
                wanneer hetzelfde dossier meerdere producten of aanvraagtypes moet bevatten.
              </CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-component px-0 sm:flex-row sm:items-center sm:justify-between">
              <p className="text-sm text-muted-foreground">
                Je keert terug naar de intentiestap en behoudt de aanvragen die hieronder
                geselecteerd blijven.
              </p>
              <Button type="button" variant="outline" onClick={draftsStep.onAddAnother}>
                Nog een aanvraag toevoegen
              </Button>
            </CardContent>
          </Card>
          <SelectChoiceCardGroup
            selectionMode="multiple"
            hint="Vink kaarten uit om ze niet mee te nemen in het aanvraagpakket."
          >
            <CardList
              items={sortedDrafts}
              widthClass="@min-[40rem]:grid-cols-1 @min-[60rem]:grid-cols-2 @min-[100rem]:grid-cols-3 @min-[150rem]:grid-cols-3"
            >
              {(draft) => (
                <SelectChoiceCard
                  key={draft.id}
                  selectionMode="multiple"
                  value={draft.id}
                  controlId={`selected-draft-${draft.id}`}
                  title={draft.label}
                  description={<DraftCardDescription draft={draft} />}
                  checked={draftsStep.includedDraftIds.includes(draft.id)}
                  onCheckedChange={(checked) => onDraftIncludedChange(draft.id, checked)}
                  emphasis="primary"
                />
              )}
            </CardList>
          </SelectChoiceCardGroup>
        </div>
      ) : null}

      {showReviewStep ? (
        <div className="space-y-4">
          <RequestPackageReview
            className="max-w-5xl"
            title={
              mode === "onboarding" ? "Samenvatting van het aanvraagpakket" : "Aanvraagdetails"
            }
            description={
              mode === "onboarding"
                ? "Alleen de inhoudelijke aanvragen staan hieronder. Vertegenwoordiger en organisatie registreer je in de volgende stap."
                : "Deze gegevens worden samen met de onboarding-intake of de gekende organisatiecontext ingediend."
            }
            requester={mode === "authenticated" ? reviewRequester : undefined}
            rows={reviewStep.rows}
            notice={
              reviewStep.draftCount > 1 ? (
                <span>
                  <Badge variant="secondary">{reviewStep.draftCount} vragen</Badge> worden samen
                  gebundeld in deze aanvraag.
                </span>
              ) : undefined
            }
          />
          <DownloadableDocumentsList
            className="max-w-5xl"
            title="Regels en documentatie"
            description={rulesetDocumentsDescription}
            items={rulesetDocuments}
            emptyContent={rulesetEmptyContent}
          />
        </div>
      ) : null}
    </StepLayout>
  );
}

